159	static void* _timer_callback(void* args)
160	{
161	  _timer_t* timer = (_timer_t*) args;
162	  struct timespec ts;
163	
164	  clock_gettime(CLOCK_MONOTONIC, &ts);
165	
166	  if (_timespec_sub(&ts, &timer->start, &ts) < 0) {
167	    printf("ERROR:_timespec_sub() failed: %ld.%.9ld > %ld.%.9ld\n",
168	           timer->start.tv_sec, timer->start.tv_nsec,
169	           ts.tv_sec, ts.tv_nsec);
170	  } else {
171	    printf("%s\t: Timer %u expired after %ld.%.9ld seconds (%u s)\n",
172	           __FUNCTION__, timer->id, ts.tv_sec, ts.tv_nsec, timer->sec);
173	    timer->id = timer_stop(timer->id);
174	    pthread_mutex_lock(&_mutex);
175	    _nb_timers -= 1;
176	    pthread_mutex_unlock(&_mutex);
177	  }
178	
179	  return NULL;
180	}
